class PerformanceShortcodeRenderer {
    public static function dashboard($atts = []): string {
        if (!is_user_logged_in()) return '<p>Por favor, inicia sessão para ver o dashboard.</p>';
        Module::maybe_install();
        $atts = shortcode_atts(['client_id'=>0,'project_id'=>0,'user_id'=>0,'date_from'=>'','date_to'=>'','title'=>'FieldFlow Growth Hub'], $atts, 'fieldflow_performance_dashboard');
        $client_id=absint($atts['client_id']); $project_id=absint($atts['project_id']); $user_id=absint($atts['user_id']);
        $date_from=preg_match('/^\d{4}-\d{2}-\d{2}$/',(string)$atts['date_from']) ? (string)$atts['date_from'] : '';
        $date_to=preg_match('/^\d{4}-\d{2}-\d{2}$/',(string)$atts['date_to']) ? (string)$atts['date_to'] : '';
        $summary=Module::performance_summary($client_id,$project_id,$user_id,$date_from,$date_to);
        $top=$summary['top']; $risk=$summary['risk']; $timeline=$summary['timeline']; $activity=$summary['activity'] ?? []; $configured_skills=Module::skill_matrix_values($client_id,$project_id,$user_id); $skills=$configured_skills ?: self::skill_matrix($summary);
        $scope_bits=[];
        $scope_bits[]=$client_id ? 'Cliente #'.$client_id : 'Todos os clientes';
        $scope_bits[]=$project_id ? 'Campanha #'.$project_id : 'Todas as campanhas';
        if($user_id) $scope_bits[]='Operacional #'.$user_id;
        if($date_from || $date_to) $scope_bits[]=trim(($date_from ?: 'início').' → '.($date_to ?: 'hoje'));
        $scope_label=implode(' · ',$scope_bits);
        $readiness=(int)$summary['readiness'];
        $readiness_label=$readiness>=80?'Alta prontidão':($readiness>=60?'Prontidão moderada':'Risco operacional');
        ob_start(); ?>
