rn;root.querySelectorAll('[data-feed-pager]').forEach(function(pager){pager.addEventListener('click',function(e){var btn=e.target.closest('[data-feed-target]');if(!btn)return;var page=btn.getAttribute('data-feed-target');root.querySelectorAll('.ffp-feed-row').forEach(function(r){r.classList.toggle('is-hidden',r.getAttribute('data-feed-page')!==page);});pager.querySelectorAll('.ffp-feed-page').forEach(function(b){b.classList.toggle('is-active',b===btn);});});});})();</script><?php endif; ?></div></div></div>
