    private static function skill_matrix(array $summary): array {
        $academy = (int)($summary['academy_rate'] ?? 0);
        $mission = (int)($summary['mission_rate'] ?? 0);
        $cert = (int)($summary['cert_rate'] ?? 0);
        $readiness = (int)($summary['readiness'] ?? 0);
        $score = (int)($summary['avg_score'] ?? 0);
        return [
            'Conhecimento de Produto' => min(100, max(0, round(($academy * 0.75) + ($cert * 0.25)))),
            'Execução no Terreno' => min(100, max(0, round(($mission * 0.80) + ($readiness * 0.20)))),
            'Disciplina Operacional' => min(100, max(0, round(($mission * 0.55) + ($academy * 0.25) + ($cert * 0.20)))),
            'Certificação' => min(100, max(0, $cert)),
            'Readiness Global' => min(100, max(0, round(($readiness * 0.70) + ($score * 0.30)))),
        ];
    }

    private static function kpi(string $label, $value, string $small): void { echo '<div class="ffp-card ffp-kpi"><span>'.esc_html($label).'</span><strong>'.esc_html((string)$value).'</strong><small>'.esc_html($small).'</small></div>'; }

    public static function academy($atts = []): string {
        if (!is_user_logged_in()) return '<p>Por favor, inicia sessão para aceder à Academy.</p>';
        Module::maybe_install(); global $wpdb;
        $atts=shortcode_atts(['client_id'=>0,'project_id'=>0],$atts,'fieldflow_academy');
        $client_id=absint($atts['client_id']); $project_id=absint($atts['project_id']); $user_id=get_current_user_id();
        if(!Module::user_in_scope($user_id,$client_id,$project_id)) return '<div class="ffp-academy"><p>Não existem conteúdos Academy atribuídos ao teu utilizador neste âmbito.</p></div>';
        $courses=Module::get_courses(['client_id'=>$client_id,'project_id'=>$project_id,'user_id'=>$user_id]);
        $missions=Module::get_missions(['client_id'=>$client_id,'project_id'=>$project_id,'user_id'=>$user_id]);
        $badges=Module::get_user_badges($user_id);
        $next_course=null; $total_courses=count($courses); $completed_courses=0; $avg=0;
        foreach($courses as $cc){ $cp=Module::course_completion((int)$cc['id'],$user_id); $avg+=(int)$cp['percent']; if(!empty($cp['complete'])) $completed_courses++; if(!$next_course && empty($cp['complete'])) $next_course=$cc; }
        $avg=$total_courses?round($avg/$total_courses):0;
        ob_start(); ?>
