ground:#ecfdf5;border:1px solid #a7f3d0;border-radius:16px;padding:12px;color:#065f46;font-weight:900}.ffp-mission-submitted{background:#eff6ff;border:1px solid #bfdbfe;border-radius:16px;padding:12px;color:#1d4ed8;font-weight:900}.ffp-mission-content,.ffp-mission-quiz{border:1px solid #e2e8f0;border-radius:18px;background:#fff;padding:12px;margin:12px 0}.ffp-mission-quiz strong,.ffp-mission-content strong{display:block;margin-bottom:6px}.ffp-quiz-question{display:block;margin:10px 0}.ffp-quiz-question span{display:block;font-weight:800;margin-bottom:4px}
