<div class="ffp-academy"><div class="ffp-academy-head"><span class="ffp-pill">FieldFlow Academy Pro</span><h2>Formação prática e missões</h2><p>Continua de onde ficaste, conclui experiências obrigatórias e desbloqueia certificações.</p><div class="ffp-academy-kpis"><div class="ffp-academy-kpi"><span>Cursos</span><strong><?php echo esc_html((string)$total_courses); ?></strong></div><div class="ffp-academy-kpi"><span>Concluídos</span><strong><?php echo esc_html((string)$completed_courses); ?></strong></div><div class="ffp-academy-kpi"><span>Progresso médio</span><strong><?php echo esc_html((string)$avg); ?>%</strong></div></div></div>
<?php if($next_course): ?><div class="ffp-a-card" style="margin-bottom:16px"><span class="ffp-status live">Continuar agora</span><h3><?php echo esc_html($next_course['title']); ?></h3><p class="ffp-muted">Este é o próximo curso recomendado no teu percurso.</p></div><?php endif; ?>
<h3 class="ffp-section-title">Cursos disponíveis</h3><div class="ffp-academy-grid"><?php if(!$courses): ?><div class="ffp-a-card">Ainda não existem cursos ativos para este âmbito.</div><?php else: foreach($courses as $c): $lessons=Module::get_lessons((int)$c['id']); $completion=Module::course_completion((int)$c['id'],$user_id); $done=(int)$completion['done']; $total=count($lessons); $pct=(int)$completion['percent']; $course_complete=!empty($completion['complete']); $course_status=$course_complete?'Concluído':($pct>0?'Em curso':'Por iniciar'); ?><div class="ffp-a-card ffp-course-card"><div class="ffp-course-top"><div><h3><?php echo esc_html($c['title']); ?></h3><p class="ffp-muted"><?php echo esc_html(wp_trim_words(wp_strip_all_tags($c['description']??''),24)); ?></p></div><span class="ffp-status <?php echo $course_complete?'done':'live'; ?>"><?php echo esc_html($course_status); ?></span></div><p><span class="ffp-pill"><?php echo esc_html((string)$c['duration_min']); ?> min</span><span class="ffp-pill"><?php echo esc_html((string)$c['points']); ?> pts</span><span class="ffp-pill"><?php echo esc_html((string)$total); ?> experiências</span></p><div class="ffp-course-progress"><b style="width:<?php echo esc_attr((string)$pct); ?>%"></b></div><p class="ffp-muted"><?php echo esc_html((string)$pct); ?>% concluído, <?php echo esc_html((string)$done); ?>/<?php echo esc_html((string)$total); ?> experiências</p><?php if(!empty($completion['complete'])): $cert_url=wp_nonce_url(admin_url('admin-post.php?action=fieldflow_perf_download_certificate&course_id='.(int)$c['id']),'fieldflow_perf_download_certificate_'.(int)$c['id']); ?><p><a class="ffp-btn" href="<?php echo esc_url($cert_url); ?>">Descarregar certificado PDF</a></p><?php endif; ?><?php $prev_required_done=true; $n=0; foreach($lessons as $lesson): $n++; $status=$wpdb->get_var($wpdb->prepare("SELECT status FROM ".Module::table('lesson_progress')." WHERE lesson_id=%d AND user_id=%d AND status='completed' ORDER BY completed_at DESC,id DESC LIMIT 1",(int)$lesson['id'],$user_id)); if($course_complete){ $status='completed'; } $required=(int)($lesson['is_required']??1)===1; $locked=$required && !$prev_required_done && $status!=='completed'; $step_class=$status==='completed'?'done':($locked?'':'current'); ?><div class="ffp-lesson <?php echo $locked?'locked':''; ?>"><div class="ffp-lesson-head"><div><strong><span class="ffp-step <?php echo esc_attr($step_class); ?>"><?php echo esc_html((string)$n); ?></span><?php echo esc_html($lesson['title']); ?></strong> <span class="ffp-pill"><?php echo esc_html(strtoupper($lesson['content_type'] ?: 'link')); ?></span><?php if(!$required): ?><span class="ffp-pill">Opcional</span><?php endif; ?></div><?php if($status==='completed'): ?><span class="ffp-completed-badge">✓ Concluída</span><?php elseif($locked): ?><span class="ffp-locked-badge">Bloqueada</span><?php endif; ?></div><?php if(!empty($lesson['body'])): ?><p class="ffp-muted"><?php echo esc_html(wp_trim_words(wp_strip_all_tags($lesson['body']),22)); ?></p><?php endif; ?><?php if($locked): ?><p class="ffp-muted">Conclui a experiência obrigatória anterior para desbloquear esta lição.</p><?php else: ?><?php echo self::render_media($lesson); ?><?php if($status!=='completed'): $gate_types=['youtube','canva','pdf','link']; $gate=in_array(sanitize_key((string)$lesson['content_type']),$gate_types,true) && $required; $required_seconds=$gate ? max(0,min(600,(int)($lesson['min_watch_seconds']??8))) : 0; ?><form class="ffp-lesson-form" method="post" action="<?php echo esc_url(admin_url('admin-post.php')); ?>" data-required-seconds="<?php echo esc_attr((string)$required_seconds); ?>" onsubmit="try{sessionStorage.setItem('fieldflow_active_panel','academy')}catch(e){}"><?php wp_nonce_field('fieldflow_perf_mark_lesson'); ?><input type="hidden" name="action" value="fieldflow_perf_mark_lesson"><input type="hidden" name="lesson_id" value="<?php echo esc_attr($lesson['id']); ?>"><input type="hidden" name="course_id" value="<?php echo esc_attr($c['id']); ?>"><input type="hidden" name="ffp_panel" value="academy"><input type="hidden" name="watched_seconds" value="0"><span class="ffp-watch-note"><?php echo $required_seconds ? 'Carrega no play ou abre o conteúdo para iniciar a validação.' : ''; ?></span><button class="ffp-btn" <?php echo $required_seconds ? 'disabled' : ''; ?>><?php echo $required_seconds ? 'A desbloquear...' : 'Marcar lição como concluída'; ?></button></form><?php endif; ?><?php endif; ?></div><?php if($required && $status!=='completed') $prev_required_done=false; endforeach; ?></div><?php endforeach; endif; ?></div>

<h3 class="ffp-section-title">Os meus badges</h3><div class="ffp-badge-grid"><?php if(!$badges): ?><div class="ffp-a-card">Ainda não existem badges. Conclui um curso para desbloquear o primeiro cromo da tua caderneta.</div><?php else: foreach($badges as $b): $seal=$b['seal_image_url'] ?: ''; $cert_url=wp_nonce_url(admin_url('admin-post.php?action=fieldflow_perf_download_certificate&course_id='.(int)$b['course_id']),'fieldflow_perf_download_certificate_'.(int)$b['course_id']); ?><div class="ffp-badge-card" style="background:<?php echo esc_attr($b['card_bg_color'] ?? '#ffffff'); ?>"><div><?php if($seal): ?><img src="<?php echo esc_url($seal); ?>" alt="Badge"><?php else: ?><div style="width:86px;height:86px;border-radius:999px;margin:4px auto 10px;background:linear-gradient(135deg,var(--ffp-primary),var(--ffp-accent));display:grid;place-items:center;color:#fff;font-weight:900">FF</div><?php endif; ?></div><h4><?php echo esc_html($b['course_title']); ?></h4><small><?php echo esc_html(date_i18n('d/m/Y', strtotime($b['issued_at']))); ?></small><div class="ffp-badge-actions"><button type="button" class="ffp-badge-mini" style="background:<?php echo esc_attr($b['button_color'] ?? '#0f172a'); ?>;color:<?php echo esc_attr($b['button_text_color'] ?? '#ffffff'); ?>" data-badge-title="<?php echo esc_attr($b['course_title']); ?>" data-badge-img="<?php echo esc_url($seal); ?>" data-badge-date="<?php echo esc_attr(date_i18n('d/m/Y', strtotime($b['issued_at']))); ?>" data-badge-id="<?php echo esc_attr($b['certificate_uid']); ?>" data-badge-url="<?php echo esc_url($b['validation_url']); ?>" data-modal-bg="<?php echo esc_attr($b['modal_bg_color'] ?? '#ffffff'); ?>" data-modal-text="<?php echo esc_attr($b['modal_text_color'] ?? '#0f172a'); ?>" data-title-font="<?php echo esc_attr(\RoutesPro\Performance\Module::css_font_family((string)($b['title_font'] ?? 'Helvetica-Bold'))); ?>" data-body-font="<?php echo esc_attr(\RoutesPro\Performance\Module::css_font_family((string)($b['body_font'] ?? 'Helvetica'))); ?>">Ver badge</button><a class="ffp-badge-mini" style="background:#f1f5f9;color:#0f172a;text-decoration:none" href="<?php echo esc_url($cert_url); ?>">PDF</a></div></div><?php endforeach; endif; ?></div>

<h3 class="ffp-section-title">Missões atribuídas</h3><div class="ffp-mission-grid"><?php if(!$missions): ?><div class="ffp-mission-empty">Ainda não existem missões ativas para este âmbito.</div><?php else: foreach($missions as $m): $status=$wpdb->get_var($wpdb->prepare('SELECT status FROM '.Module::table('mission_users').' WHERE mission_id=%d AND user_id=%d',(int)$m['id'],$user_id)); $status=$status?:'assigned'; $priority=sanitize_key((string)($m['priority']??'normal')); $evtype=(string)($m['evidence_type']??'link'); $requires_ev=!empty($m['evidence_required']); $requires_approval=!empty($m['approval_required']); ?><div class="ffp-mission-card"><div class="ffp-mission-top"><span class="ffp-pill">Missão <?php echo esc_html(strtoupper((string)($m['mission_type']??'field_action'))); ?></span><span class="ffp-status <?php echo $status==='completed'?'done':'live'; ?>"><?php echo esc_html($status==='assigned'?'Por iniciar':($status==='submitted'?'Em validação':($status==='completed'?'Concluída':$status))); ?></span></div><h3 class="ffp-mission-title"><?php echo esc_html($m['title']); ?></h3><p class="ffp-muted"><?php echo esc_html(wp_trim_words(wp_strip_all_tags($m['description']??''),30)); ?></p><div class="ffp-mission-meta"><span class="ffp-pill"><?php echo esc_html((string)$m['points']); ?> pts</span><span class="ffp-pill ffp-priority <?php echo esc_attr($priority); ?>">Prioridade: <?php echo esc_html($priority==='critical'?'Crítica':($priority==='high'?'Alta':($priority==='low'?'Baixa':'Normal'))); ?></span><?php if(!empty($m['due_at'])): ?><span class="ffp-pill">Prazo: <?php echo esc_html(date_i18n('d/m H:i', strtotime($m['due_at']))); ?></span><?php endif; ?><span class="ffp-pill">Evidência: <?php echo esc_html($evtype); ?></span><?php if($requires_approval): ?><span class="ffp-pill">Validação BO</span><?php endif; ?></div><?php if(!empty($m['success_criteria'])): ?><div class="ffp-mission-criteria"><strong>Critérios de sucesso</strong><br><?php echo wp_kses_post(wpautop($m['success_criteria'])); ?></div><?php endif; ?><?php $mct=sanitize_key((string)($m['mission_content_type']??'none')); $murl=(string)($m['mission_content_url']??''); if($mct && $mct!=='none'): ?><div class="ffp-mission-content"><strong>Conteúdo da missão</strong><?php if($mct==='youtube' && $murl): $vid=Module::youtube_id($murl); ?><div class="ffp-embed ffp-video"><iframe src="https://www.youtube.com/embed/<?php echo esc_attr($vid); ?>" allowfullscreen></iframe></div><?php elseif($mct==='canva' && $murl): ?><div class="ffp-embed"><iframe src="<?php echo esc_url($murl); ?>"></iframe></div><?php elseif($mct==='pdf' && $murl): ?><div class="ffp-pdf"><iframe src="<?php echo esc_url($murl); ?>"></iframe></div><?php elseif($murl): ?><p><a class="ffp-btn" href="<?php echo esc_url($murl); ?>" target="_blank" rel="noopener">Abrir conteúdo</a></p><?php else: ?><p class="ffp-muted">Consulta a descrição e critérios da missão antes de responder ao teste.</p><?php endif; ?></div><?php endif; ?><?php if($status==='completed'): ?><div class="ffp-mission-done">✓ Missão concluída</div><?php elseif($status==='submitted'): ?><div class="ffp-mission-submitted">✓ Submetida, aguarda validação</div><?php else: ?><form class="ffp-mission-form" method="post" action="<?php echo esc_url(admin_url('admin-post.php')); ?>" onsubmit="try{sessionStorage.setItem('fieldflow_active_panel','academy')}catch(e){}"><?php wp_nonce_field('fieldflow_perf_complete_mission'); ?><input type="hidden" name="action" value="fieldflow_perf_complete_mission"><input type="hidden" name="mission_id" value="<?php echo esc_attr($m['id']); ?>"><input type="hidden" name="ffp_panel" value="academy"><?php if($requires_ev): ?><span class="ffp-evidence-required">Evidência obrigatória</span><?php endif; ?><?php $quiz=Module::parse_mission_quiz($m); if((!empty($m['quiz_enabled']) || sanitize_key((string)($m['mission_content_type']??''))==='quiz') && $quiz): ?><div class="ffp-mission-quiz"><strong>Questionário final</strong><small class="ffp-muted">Nota mínima: <?php echo esc_html((string)($m['quiz_pass_score']??70)); ?>%</small><?php foreach($quiz as $qi=>$q): ?><?php $type=sanitize_key((string)($q['type']??'multiple')); $opts=(array)($q['options']??[]); $required=!empty($q['required'])?'required':''; ?><div class="ffp-quiz-question"><span><?php echo esc_html(($qi+1).'. '.($q['question']??'')); ?><?php if(!empty($q['points'])): ?> <em><?php echo esc_html((string)$q['points']); ?> pts</em><?php endif; ?></span><?php if($type==='multiple' || $type==='truefalse'): ?><select class="ffp-text" name="quiz_answers[<?php echo esc_attr((string)$qi); ?>]" <?php echo esc_attr($required); ?>><option value="">Selecionar</option><?php foreach($opts as $op): ?><option value="<?php echo esc_attr($op); ?>"><?php echo esc_html($op); ?></option><?php endforeach; ?></select><?php elseif($type==='checklist'): ?><div class="ffp-checklist-options"><?php foreach($opts as $op): ?><label><input type="checkbox" name="quiz_answers[<?php echo esc_attr((string)$qi); ?>][]" value="<?php echo esc_attr($op); ?>"> <?php echo esc_html($op); ?></label><?php endforeach; ?></div><?php elseif($type==='scale'): ?><select class="ffp-text" name="quiz_answers[<?php echo esc_attr((string)$qi); ?>]" <?php echo esc_attr($required); ?>><option value="">Selecionar</option><?php foreach(($opts?:['1','2','3','4','5']) as $op): ?><option value="<?php echo esc_attr($op); ?>"><?php echo esc_html($op); ?></option><?php endforeach; ?></select><?php elseif($type==='long'): ?><textarea class="ffp-text" name="quiz_answers[<?php echo esc_attr((string)$qi); ?>]" rows="3" <?php echo esc_attr($required); ?> placeholder="Resposta"></textarea><?php elseif($type==='evidence'): ?><input class="ffp-text" name="quiz_answers[<?php echo esc_attr((string)$qi); ?>]" <?php echo esc_attr($required); ?> placeholder="Link ou descrição da evidência"><?php else: ?><input class="ffp-text" name="quiz_answers[<?php echo esc_attr((string)$qi); ?>]" <?php echo esc_attr($required); ?> placeholder="Resposta"><?php endif; ?></div><?php endforeach; ?></div><?php endif; ?><input class="ffp-text" name="evidence_url" <?php echo $requires_ev?'required':''; ?> placeholder="Link de evidência, <?php echo esc_attr($evtype); ?>"><textarea class="ffp-text" name="note" rows="4" placeholder="Nota de execução, aprendizagens ou contexto"></textarea><button class="ffp-btn"><?php echo $requires_approval?'Submeter para validação':'Marcar como concluída'; ?></button></form><?php endif; ?></div><?php endforeach; endif; ?></div></div><div class="ffp-modal-backdrop" id="ffpBadgeModal" aria-hidden="true"><div class="ffp-modal" role="dialog" aria-modal="true"><button class="ffp-modal-close" type="button">×</button><div class="ffp-modal-premium"><div class="ffp-modal-badge-col"><div class="ffp-modal-orbit"><div id="ffpBadgeModalImage"></div></div><span class="ffp-modal-chip">Badge conquistado</span></div><div class="ffp-modal-info-col"><small class="ffp-modal-kicker">FieldFlow Academy</small><h3 id="ffpBadgeModalTitle"></h3><p class="ffp-muted">Este badge faz parte da tua caderneta de formação e está associado ao certificado emitido.</p><div class="ffp-modal-meta"><div><small>Data</small><strong id="ffpBadgeModalDate"></strong></div><div><small>ID</small><strong id="ffpBadgeModalId"></strong></div></div><div class="ffp-modal-actions"><a id="ffpBadgeModalVerify" class="ffp-btn" target="_blank" rel="noopener">Verificar certificado</a></div></div></div></div></div>

<style id="ffp-youtube-cover-css">
.ffp-youtube-cover{position:relative;background:#0f172a;overflow:hidden;border-radius:18px;aspect-ratio:16/9;min-height:220px}.ffp-youtube-cover iframe{position:absolute;inset:0;width:100%;height:100%;border:0}.ffp-youtube-play{position:absolute;inset:0;width:100%;height:100%;border:0;background:#0f172a;cursor:pointer;padding:0;display:block}.ffp-youtube-play img{width:100%;height:100%;object-fit:cover;display:block;filter:saturate(1.04) contrast(1.02)}.ffp-youtube-play:after{content:"";position:absolute;inset:0;background:linear-gradient(180deg,rgba(15,23,42,.05),rgba(15,23,42,.24))}.ffp-youtube-play span{position:absolute;left:50%;top:50%;transform:translate(-50%,-50%);z-index:2;width:72px;height:72px;border-radius:999px;background:rgba(255,255,255,.94);color:#0f172a;display:flex;align-items:center;justify-content:center;font-size:28px;box-shadow:0 20px 45px rgba(15,23,42,.32);padding-left:4px}.ffp-youtube-play:hover span{transform:translate(-50%,-50%) scale(1.04)}
@media(max-width:760px){.ffp-youtube-cover{min-height:0!important}.ffp-youtube-play span{width:58px;height:58px;font-size:23px}}
.ffp-modal{overflow:hidden;border:1px solid rgba(226,232,240,.9)}.ffp-modal:before{content:"";position:absolute;inset:0;background:radial-gradient(circle at 18% 18%,rgba(217,164,65,.16),transparent 32%),linear-gradient(135deg,rgba(248,250,252,.88),rgba(255,255,255,.98));pointer-events:none}.ffp-modal>*{position:relative}.ffp-modal-premium{display:grid;grid-template-columns:minmax(190px,250px) 1fr;gap:24px;align-items:center;padding:18px 8px 8px}.ffp-modal-badge-col{text-align:center}.ffp-modal-orbit{width:190px;height:190px;border-radius:36px;margin:0 auto 14px;display:grid;place-items:center;background:linear-gradient(145deg,rgba(255,255,255,.98),rgba(248,250,252,.92));border:1px solid rgba(226,232,240,.95);box-shadow:inset 0 0 0 8px rgba(255,255,255,.58),0 24px 55px rgba(15,23,42,.16)}.ffp-modal-orbit img{max-width:145px;max-height:145px;object-fit:contain;display:block}.ffp-modal-chip{display:inline-flex;border-radius:999px;padding:8px 12px;background:#ecfeff;color:#155e75;font-weight:900;font-size:12px}.ffp-modal-kicker{display:block;text-transform:uppercase;letter-spacing:.14em;font-weight:900;color:#64748b;margin-bottom:8px}.ffp-modal-info-col{text-align:left}.ffp-modal-info-col h3{text-align:left;margin-top:0}.ffp-modal-info-col .ffp-muted{font-size:15px;line-height:1.55}.ffp-modal-meta div{background:rgba(248,250,252,.92)}@media(max-width:720px){.ffp-modal{border-radius:24px;padding:18px;max-height:92vh;overflow:auto}.ffp-modal-premium{grid-template-columns:1fr;text-align:center;gap:14px}.ffp-modal-info-col,.ffp-modal-info-col h3{text-align:center}.ffp-modal-orbit{width:150px;height:150px;border-radius:30px}.ffp-modal-orbit img{max-width:112px;max-height:112px}.ffp-modal-actions{justify-content:center}}

</style>

<script>
(function(){
function keepAcademy(){try{sessionStorage.setItem('fieldflow_active_panel','academy');}catch(e){}}
function startLessonGateFrom(el){var lesson=el&&el.closest?el.closest('.ffp-lesson'):null;if(!lesson)return;var form=lesson.querySelector('.ffp-lesson-form[data-required-seconds]');if(form){form.dispatchEvent(new CustomEvent('ffp:start-gate',{bubbles:false}));}}
function initYouTubeCovers(){document.querySelectorAll('.ffp-youtube-cover[data-embed]').forEach(function(box){if(box.dataset.ready==='1')return;box.dataset.ready='1';var img=box.querySelector('img[data-fallback]');if(img){img.addEventListener('error',function(){var fb=img.getAttribute('data-fallback');if(fb&&img.src!==fb){img.src=fb;}});}var btn=box.querySelector('.ffp-youtube-play');if(!btn)return;btn.addEventListener('click',function(){var src=box.getAttribute('data-embed')||'';if(!src)return;startLessonGateFrom(box);var iframe=document.createElement('iframe');iframe.src=src+(src.indexOf('?')>-1?'&':'?')+'autoplay=1';iframe.allow='accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share';iframe.allowFullscreen=true;box.innerHTML='';box.appendChild(iframe);});});}
function initAcademyGates(){document.querySelectorAll('.ffp-lesson-form[data-required-seconds]').forEach(function(form){if(form.dataset.gateReady==='1')return;form.dataset.gateReady='1';var required=parseInt(form.getAttribute('data-required-seconds')||'0',10);var input=form.querySelector('input[name="watched_seconds"]');var btn=form.querySelector('button.ffp-btn');var note=form.querySelector('.ffp-watch-note');var elapsed=0;var timer=null;var started=false;if(!btn||!input){return;}function unlock(){if(note){note.textContent='Conteúdo pronto para conclusão.';}btn.disabled=false;btn.textContent='Marcar lição como concluída';if(timer){clearInterval(timer);timer=null;}}
function tick(){elapsed++;input.value=String(elapsed);var left=Math.max(0,required-elapsed);if(left>0){if(note){note.textContent='A visualizar conteúdo. Podes concluir em '+left+'s.';}btn.disabled=true;btn.textContent='A desbloquear...';}else{unlock();}}
function startGate(){if(started||!required)return;started=true;elapsed=0;input.value='0';tick();timer=setInterval(tick,1000);}if(!required){form.addEventListener('submit',keepAcademy);return;}btn.disabled=true;btn.textContent='Bloqueado';if(note){note.textContent='Carrega no play ou abre o conteúdo para iniciar a validação.';}form.addEventListener('ffp:start-gate',startGate);var lesson=form.closest('.ffp-lesson');if(lesson){lesson.querySelectorAll('a.ffp-btn').forEach(function(a){if(a.dataset.gateLink==='1')return;a.dataset.gateLink='1';a.addEventListener('click',function(){startGate();});});var iframe=lesson.querySelector('.ffp-pdf iframe');if(iframe){iframe.addEventListener('load',function(){startGate();});}}
form.addEventListener('submit',function(e){keepAcademy();if(required&&parseInt(input.value||'0',10)<required){e.preventDefault();if(note){note.textContent=started?'Ainda falta consumir o conteúdo antes de concluir.':'Primeiro carrega no play ou abre o conteúdo.';}}});});document.querySelectorAll('form input[name="ffp_panel"][value="academy"]').forEach(function(inp){var form=inp.closest('form');if(form&&form.dataset.keepPanel!=='1'){form.dataset.keepPanel='1';form.addEventListener('submit',keepAcademy);}});}
function initBadgeModal(){var modal=document.getElementById('ffpBadgeModal');if(!modal||modal.dataset.ready==='1')return;modal.dataset.ready='1';var close=modal.querySelector('.ffp-modal-close');function hide(){modal.classList.remove('is-open');modal.setAttribute('aria-hidden','true');}if(close)close.addEventListener('click',hide);modal.addEventListener('click',function(e){if(e.target===modal)hide();});document.querySelectorAll('.ffp-badge-mini[data-badge-title]').forEach(function(btn){btn.addEventListener('click',function(){var title=btn.getAttribute('data-badge-title')||'';var img=btn.getAttribute('data-badge-img')||'';var date=btn.getAttribute('data-badge-date')||'';var id=btn.getAttribute('data-badge-id')||'';var url=btn.getAttribute('data-badge-url')||'#';var bg=btn.getAttribute('data-modal-bg')||'#ffffff';var text=btn.getAttribute('data-modal-text')||'#0f172a';var titleFont=btn.getAttribute('data-title-font')||'';var bodyFont=btn.getAttribute('data-body-font')||'';var box=modal.querySelector('.ffp-modal');box.style.background=bg;box.style.color=text;if(bodyFont){box.style.fontFamily=bodyFont;}var titleEl=modal.querySelector('#ffpBadgeModalTitle');if(titleFont){titleEl.style.fontFamily=titleFont;}titleEl.textContent=title;modal.querySelector('#ffpBadgeModalDate').textContent=date;modal.querySelector('#ffpBadgeModalId').textContent=id;modal.querySelector('#ffpBadgeModalVerify').href=url;var holder=modal.querySelector('#ffpBadgeModalImage');holder.innerHTML=img?'<img src="'+img.replace(/"/g,'&quot;')+'" alt="Badge">':'<div style="width:130px;height:130px;border-radius:999px;margin:auto;background:linear-gradient(135deg,#0f172a,#2563eb);display:grid;place-items:center;color:#fff;font-weight:900;font-size:32px">FF</div>';modal.classList.add('is-open');modal.setAttribute('aria-hidden','false');});});}
function init(){initYouTubeCovers();initAcademyGates();initBadgeModal();}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',init);}else{init();}
document.addEventListener('routespro:panel-open',function(e){if(e&&e.detail&&e.detail.panel==='academy')setTimeout(init,60);});
})();
</script>
<?php return ob_get_clean();
    }

    private static function youtube_embed(string $url): string {
        $id='';
        if(preg_match('~youtu\.be/([A-Za-z0-9_-]+)~',$url,$m)) $id=$m[1];
        elseif(preg_match('~v=([A-Za-z0-9_-]+)~',$url,$m)) $id=$m[1];
        elseif(preg_match('~/embed/([A-Za-z0-9_-]+)~',$url,$m)) $id=$m[1];
        return $id ? 'https://www.youtube.com/embed/'.$id : '';
    }

    private static function canva_embed(string $url): string {
        return 'https://www.canva.com/design/'.rawurlencode($url);
    }

    private static function render_media(array $lesson): string {
        $url = (string)($lesson['media_url'] ?: ($lesson['library_url'] ?? ''));
        $type = sanitize_key((string)($lesson['content_type'] ?: ($lesson['library_type'] ?? 'link')));
        if(!$url) return '';
        if($type==='youtube') { $embed=self::youtube_embed($url); if($embed) { $id=''; if(preg_match('~/embed/([A-Za-z0-9_-]+)~',$embed,$mm)) $id=$mm[1]; $thumb=$id ? 'https://i.ytimg.com/vi/'.$id.'/maxresdefault.jpg' : ''; return '<div class="ffp-embed ffp-video ffp-youtube ffp-youtube-cover" data-youtube-id="'.esc_attr($id).'" data-embed="'.esc_url($embed).'?rel=0&modestbranding=1"><button type="button" class="ffp-youtube-play" aria-label="Reproduzir vídeo"><img src="'.esc_url($thumb).'" data-fallback="'.esc_url($id ? 'https://i.ytimg.com/vi/'.$id.'/hqdefault.jpg' : '').'" alt="" loading="eager"><span>▶</span></button></div>'; } }
        if($type==='pdf') return '<div class="ffp-embed ffp-pdf"><iframe src="'.esc_url($url).'" loading="lazy"></iframe></div><p><a class="ffp-btn" href="'.esc_url($url).'" target="_blank" rel="noopener">Abrir PDF</a></p>';
        if($type==='canva') return '<p><a class="ffp-btn" href="'.esc_url($url).'" target="_blank" rel="noopener">Abrir apresentação Canva</a></p>';
        return '<p><a class="ffp-btn" href="'.esc_url($url).'" target="_blank" rel="noopener">Abrir conteúdo</a></p>';
    }
}
